    def _is_safe_javascript(self, js_expression):
        """
        Basic safety check for JavaScript expressions
        """
        # Prevent common dangerous patterns
        dangerous_patterns = [
            r'\b(eval|Function|setTimeout|setInterval|exec|spawn|child_process)\b',
            r'\b(document|window|global)\b',
            r'new\s+Function',
            r'\b(alert|prompt|confirm)\b',
            r'javascript:',
            r'import\s+',
            r'require\s*\(',
            r'process\.',
            r'__proto__',
            r'\bconstructor\b'
        ]
        
        # Check for dangerous patterns
        for pattern in dangerous_patterns:
            if re.search(pattern, js_expression, re.IGNORECASE):
                return False
                
        # Check for excessive complexity
        if len(js_expression) > 1000:
            return False
            
        # Check for balanced parentheses and braces
        if not self._is_balanced(js_expression):
            return False
            
        return True
    
    def _is_balanced(self, js_expression):
        """
        Check if parentheses and braces are balanced
        """
        stack = []
        for char in js_expression:
            if char in '({[':
                stack.append(char)
            elif char in ')}]':
                if not stack:
                    return False
                if (char == ')' and stack[-1] != '(') or \
                   (char == '}' and stack[-1] != '{') or \
                   (char == ']' and stack[-1] != '['):
                    return False
                stack.pop()
        return len(stack) == 0
    
